solutions.cpp:
#include <iostream>
#include <vector>
#include <unordered_set>

using namespace std;

class Solution {
public:
  int findDuplicate(vector<int>& nums) {
    unordered_set<int> num_set;
    for (int num : nums) {
      if (num_set.find(num) != num_set.end()) {
        return num;
      }
      num_set.insert(num);
    }
    return -1;
  }
};
